// Generated by UntilizeCodegen — BRISC writer for column-parallel untilize.
// Each core writes a partial stick (column chunk) at an offset within each row.
// Used when Wt is large but total_tile_rows is small (e.g. 1x1x32x7328), and
// for the 2D (tile-row x column-block) split where each core owns exactly ONE
// tile-row's column block: start_stick is the absolute output row base
// (tile_row * TILE_H) so a core writes output sticks [start_stick, start_stick +
// num_sticks). Every output byte is addressed absolutely (get_noc_addr on the
// absolute stick id, + offset_bytes within it), so any partition of the
// (tile-row x column) space writes disjoint regions with no ordering coupling.
//
// CT args: [cb_out, full_stick_size, TensorAccessor...]
// RT args: [dst_addr, num_sticks, offset_bytes, chunk_size_bytes, tiles_per_core, start_stick]
#include "api/dataflow/dataflow_api.h"

void kernel_main() {
    const uint32_t dst_addr = get_arg_val<uint32_t>(0);
    const uint32_t num_sticks = get_arg_val<uint32_t>(1);    // TILE_H per tile-row
    const uint32_t offset_bytes = get_arg_val<uint32_t>(2);  // byte offset within stick
    const uint32_t chunk_size = get_arg_val<uint32_t>(3);    // tiles_per_core * TILE_W * elem_size
    const uint32_t tiles_per_core = get_arg_val<uint32_t>(4);
    const uint32_t start_stick = get_arg_val<uint32_t>(5);  // absolute output row base (tile_row * TILE_H)

    constexpr uint32_t cb_out = get_compile_time_arg_val(0);
    constexpr uint32_t full_stick_size = get_compile_time_arg_val(1);
    constexpr auto dst_args = TensorAccessorArgs<2>();

    constexpr uint32_t WRITE_BATCH = 8;

    // ``full_stick_size`` is the logical row width, not necessarily the
    // interleaved buffer's aligned physical page pitch.
    const uint32_t destination_page_size = dst_args.get_aligned_page_size();
    const auto d = TensorAccessor(dst_args, dst_addr, destination_page_size);

    cb_wait_front(cb_out, tiles_per_core);
    uint32_t l1_read_addr = get_read_ptr(cb_out);
    uint32_t writes_pending = 0;

    for (uint32_t row = 0; row < num_sticks; ++row) {
        uint64_t dst_noc_addr = get_noc_addr(start_stick + row, d);
        dst_noc_addr += offset_bytes;
        noc_async_write(l1_read_addr, dst_noc_addr, chunk_size);
        l1_read_addr += chunk_size;
        writes_pending++;

        if (writes_pending == WRITE_BATCH) {
            noc_async_writes_flushed();
            writes_pending = 0;
        }
    }

    // ``noc_async_writes_flushed`` only drains the command queue; it does not
    // prove the NOC has finished reading this CB page.  Always fence before the
    // pop, including the exact-multiple-of-WRITE_BATCH case where
    // writes_pending is zero.
    noc_async_write_barrier();

    cb_pop_front(cb_out, tiles_per_core);
}
